
(function installMfrInvoiceManagementPatch(){
  const MFR_INVOICE_LOGO_ENCODED = 'data:image/png;base64,';
  const esc = v => String(v ?? '').replace(/[&<>"']/g, m => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
  const money = v => '$' + Number(v || 0).toLocaleString(undefined, {minimumFractionDigits:2, maximumFractionDigits:2});
  const date = v => { if(!v) return '—'; try{ return new Date(String(v).includes('T') ? v : v + 'T00:00:00').toLocaleDateString(); }catch(e){ return esc(v); } };
  const cname = c => { if(!c) return ''; return ((c.first_name||'') + ' ' + (c.last_name||'')).trim() || c.name || c.customer_name || ''; };
  const addr = (c,j) => {
    const parts=[];
    if(c?.address) parts.push(c.address);
    const cityStateZip = [c?.city,c?.state,c?.zip].filter(Boolean).join(' ');
    if(cityStateZip) parts.push(cityStateZip);
    if(!parts.length && j?.address) parts.push(j.address);
    return parts.join('<br>') || 'Project address on file';
  };
  async function invoiceRows(){
    let res = await _sb.from('v_invoices_full').select('*').order('created_at', {ascending:false}).limit(100);
    if(res.error) res = await _sb.from('invoices').select('*').order('created_at', {ascending:false}).limit(100);
    return res.error ? [] : (res.data || []);
  }
  async function estimateRows(){
    let res = await _sb.from('v_estimates_full').select('*').order('created_at', {ascending:false}).limit(100);
    if(res.error) res = await _sb.from('estimates').select('*').order('created_at', {ascending:false}).limit(100);
    return res.error ? [] : (res.data || []);
  }
  async function loadInvoiceBundle(id){
    const invRes = await _sb.from('invoices').select('*').eq('id', id).single();
    if(invRes.error) throw invRes.error;
    const invoice = invRes.data;
    let customer=null, job=null, items=[], pays=[];
    if(invoice.customer_id){ const r=await _sb.from('customers').select('*').eq('id', invoice.customer_id).maybeSingle(); if(!r.error) customer=r.data; }
    if(invoice.job_id){ const r=await _sb.from('jobs').select('*').eq('id', invoice.job_id).maybeSingle(); if(!r.error) job=r.data; }
    let q = await _sb.from('estimate_line_items').select('*').eq('invoice_id', id).order('display_order',{ascending:true}).order('created_at',{ascending:true});
    if(q.error || !q.data || !q.data.length){
      if(invoice.estimate_id) q = await _sb.from('estimate_line_items').select('*').eq('estimate_id', invoice.estimate_id).order('display_order',{ascending:true}).order('created_at',{ascending:true});
    }
    items = q.error ? [] : (q.data || []);
    if(!items.length) items = [{item_name:'Roofing project invoice', description: invoice.notes || 'Invoice generated from accepted estimate.', quantity:1, unit_label:'job', unit_price:invoice.total_amount||0, total_price:invoice.total_amount||0}];
    try{ const pr = await _sb.from('invoice_payments').select('*').eq('invoice_id', id).order('created_at',{ascending:false}); if(!pr.error) pays=pr.data||[]; }catch(e){}
    return {invoice, customer, job, items, pays};
  }
  function renderInvoiceDoc(b){
    const i=b.invoice,c=b.customer,j=b.job,items=b.items||[],pays=b.pays||[];
    const customerName = cname(c) || i.customer_name || 'Customer';
    const total = Number(i.total_amount || i.subtotal || 0);
    const paid = Number(i.amount_paid || 0) || pays.reduce((s,p)=>s+Number(p.amount||0),0);
    const balance = Number((i.balance_due ?? (total-paid)) || 0);
    const deposit = total * .5;
    const itemRows = items.map((it,idx)=>{
      const qty = Number(it.quantity||0), unit=it.unit_label || it.unit || 'item', unitPrice=Number(it.unit_price||0), lineTotal=Number(it.total_price ?? (qty*unitPrice) ?? 0);
      return '<tr><td><div class="mfr-invoice-item-title">'+esc(it.item_name||it.name||('Line Item '+(idx+1)))+'</div>'+(it.description?'<div class="mfr-invoice-item-desc">'+esc(it.description)+'</div>':'')+'</td><td class="num">'+(qty?qty.toLocaleString():'—')+' '+esc(unit)+'</td><td class="num">'+money(unitPrice)+'</td><td class="num"><strong>'+money(lineTotal)+'</strong></td></tr>';
    }).join('');
    return '<div class="mfr-invoice-doc" id="mfr-invoice-print-doc">'
      + '<div class="mfr-invoice-hero"><div class="mfr-invoice-brand"><img class="mfr-invoice-logo" src="'+MFR_INVOICE_LOGO_ENCODED+'" alt="My Family Roofer logo"><div><h2>My Family Roofer</h2><p>Protecting Your Home Like Family<br>Brian Barnes · (970) 292-6927 · brian@myfamilyroofer.com</p></div></div><div class="mfr-invoice-title"><div class="label">Invoice</div><div class="num">'+esc(i.invoice_number||'INV')+'</div></div></div>'
      + '<div class="mfr-invoice-body"><div class="mfr-invoice-topgrid"><div class="mfr-invoice-info-card"><h4>From</h4><strong>My Family Roofer</strong><p>Brian Barnes<br>2515 Baxter Place<br>Fort Collins, CO 80526<br>brian@myfamilyroofer.com<br>(970) 292-6927</p></div><div class="mfr-invoice-info-card"><h4>Bill To</h4><strong>'+esc(customerName)+'</strong><p>'+addr(c,j)+(c?.email?'<br>'+esc(c.email):'')+(c?.phone?'<br>'+esc(c.phone):'')+'</p></div><div class="mfr-invoice-info-card"><h4>Project</h4><strong>'+esc(j?.job_type||'Roof Replacement')+'</strong><p>'+addr(c,j)+'<br>Status: '+esc(j?.status||i.status||'sent')+'</p></div></div>'
      + '<div class="mfr-invoice-metadata"><div><span>Invoice Date</span><b>'+date(i.invoice_date||i.created_at)+'</b></div><div><span>Due Date</span><b>'+date(i.due_date)+'</b></div><div><span>Status</span><b>'+esc(String(i.status||'sent').toUpperCase())+'</b></div><div><span>Balance Due</span><b>'+money(balance)+'</b></div></div>'
      + '<div class="mfr-invoice-table-wrap"><table class="mfr-invoice-table"><thead><tr><th>Description</th><th class="num">Qty</th><th class="num">Rate</th><th class="num">Amount</th></tr></thead><tbody>'+itemRows+'</tbody></table></div>'
      + '<div class="mfr-invoice-totalbox"><div class="row"><span>Subtotal</span><strong>'+money(i.subtotal||total)+'</strong></div><div class="row"><span>Deposit / Payment Applied</span><strong>'+money(paid||0)+'</strong></div><div class="row"><span>Suggested 50% Deposit</span><strong>'+money(deposit)+'</strong></div><div class="row grand"><span>Balance Due</span><strong>'+money(balance)+'</strong></div></div>'
      + '<div class="mfr-invoice-terms"><div class="mfr-invoice-note"><h4>Payment & Insurance Work</h4><p>Payment is based on the final price mutually agreed upon with the insurance company for the approved scope of work, plus any selected add-ons or upgrades.</p></div><div class="mfr-invoice-note"><h4>Late Payment Policy</h4><p>Unpaid balances remaining 30 days or more from the invoice date may be subject to a 3% late fee every 30 days until paid in full.</p></div></div>'
      + '<div class="mfr-invoice-footer"><div><b>My Family Roofer</b><span class="muted">2515 Baxter Place, Fort Collins, CO 80526</span></div><div><b>Thank you for trusting us with your home.</b><span class="muted">Protecting Your Home Like Family</span></div></div></div></div>';
  }
  function renderInvoiceTable(rows){
    if(!rows.length) return '<div class="mfr-invoice-empty"><div class="big">🧾</div><strong>No invoices yet</strong><p>Convert an estimate to an invoice and it will appear here.</p></div>';
    return '<div class="mfr-invoice-mgmt-toolbar"><input class="mfr-invoice-search" id="mfr-invoice-search" placeholder="Search invoices, customers, status..." oninput="mfrFilterInvoices()"><span class="muted">'+rows.length+' invoice(s)</span></div>'
      + '<div class="mfr-invoice-table-wrap-app"><table class="mfr-invoice-app-table"><thead><tr><th>Invoice</th><th>Customer</th><th>Date</th><th>Due</th><th>Status</th><th>Total</th><th>Balance</th><th></th></tr></thead><tbody id="mfr-invoice-table-body">'
      + rows.map(i => invoiceRow(i)).join('') + '</tbody></table></div>';
  }
  function invoiceRow(i){
    const st=String(i.status||'sent').toLowerCase();
    const search=[i.invoice_number,i.customer_name,i.status,i.total_amount,i.balance_due].join(' ').toLowerCase();
    return '<tr data-invoice-row data-search="'+esc(search)+'"><td><strong>'+esc(i.invoice_number||'Invoice')+'</strong><br><small>'+esc(i.id||'')+'</small></td><td>'+esc(i.customer_name||i.customer_full_name||'Customer')+'</td><td>'+date(i.invoice_date||i.created_at)+'</td><td>'+date(i.due_date)+'</td><td><span class="mfr-invoice-status '+esc(st)+'">'+esc(st)+'</span></td><td><strong>'+money(i.total_amount||0)+'</strong></td><td><strong>'+money((i.balance_due ?? i.total_amount)||0)+'</strong></td><td><div class="mfr-invoice-actions-row"><button class="btn btn-sm btn-primary" onclick="viewInvoiceModal(&quot;'+esc(i.id)+'&quot;)">View</button><button class="btn btn-sm btn-outline" onclick="mfrPrintBrandedInvoice(&quot;'+esc(i.id)+'&quot;)">Print</button><button class="btn btn-sm btn-success" onclick="markInvoicePaid(&quot;'+esc(i.id)+'&quot;)" '+(st==='paid'?'disabled':'')+'>Paid</button><button class="btn btn-sm btn-danger" onclick="confirmDeleteInvoice(&quot;'+esc(i.id)+'&quot;)">Delete</button></div></td></tr>';
  }
  function renderEstimateTable(rows){
    if(window.mfrRenderEstimateTable) return window.mfrRenderEstimateTable(rows);
    if(!rows.length) return '<p style="color:var(--text3)">No saved estimates yet.</p>';
    return '<table class="tbl"><thead><tr><th>Estimate</th><th>Customer</th><th>Status</th><th>Total</th><th>Date</th><th></th></tr></thead><tbody>' + rows.map(e => '<tr><td><strong>'+esc(e.estimate_number||'Estimate')+'</strong></td><td>'+esc(e.customer_name||'')+'</td><td>'+esc(e.status||'draft')+'</td><td><strong>'+money(e.total_amount||0)+'</strong></td><td>'+date(e.estimate_date||e.created_at)+'</td><td><button class="btn btn-sm btn-primary" onclick="viewEstimateModal(&quot;'+esc(e.id)+'&quot;)">View</button></td></tr>').join('') + '</tbody></table>';
  }
  window.mfrFilterInvoices = function(){
    const q=(document.getElementById('mfr-invoice-search')?.value||'').trim().toLowerCase();
    document.querySelectorAll('[data-invoice-row]').forEach(row => row.style.display = !q || row.dataset.search.includes(q) ? '' : 'none');
  };
  window.pageEstimatesList = async function(c){
    c = c || document.getElementById('content'); if(!c) return;
    c.innerHTML = '<div class="page-wrap"><div class="page-hd"><div><div class="page-title">Estimates & Invoices</div><div class="page-sub">Saved quotes, invoice creation, payment status, and invoice cleanup.</div></div><button class="btn btn-primary" onclick="go(&quot;estimates&quot;)">+ New Estimate</button></div><div class="card"><div class="card-hd"><div><div class="card-hd-title">Invoices</div><div class="card-sub">View, print, mark paid, or delete invoices.</div></div></div><div class="card-body" id="mfr-inv-list">Loading invoices...</div></div><div class="card"><div class="card-hd"><div><div class="card-hd-title">Saved Estimates</div><div class="card-sub">Quotes and drafts that can be converted to invoices.</div></div></div><div class="card-body" id="mfr-est-list">Loading estimates...</div></div></div>';
    try{
      const [invoices, estimates] = await Promise.all([invoiceRows(), estimateRows()]);
      const invEl=document.getElementById('mfr-inv-list'), estEl=document.getElementById('mfr-est-list');
      if(invEl) invEl.innerHTML = renderInvoiceTable(invoices);
      if(estEl) estEl.innerHTML = renderEstimateTable(estimates);
    }catch(e){ toast('Could not load estimates/invoices: '+(e.message||e), 'error'); }
  };
  window.viewInvoiceModal = async function(id){
    try{
      const b=await loadInvoiceBundle(id), i=b.invoice;
      const paidDisabled=String(i.status||'').toLowerCase()==='paid' ? 'disabled' : '';
      const actions='<div class="mfr-invoice-actions"><button class="btn btn-success" '+paidDisabled+' onclick="markInvoicePaid(&quot;'+esc(i.id)+'&quot;)">Mark Paid</button><button class="btn btn-primary" onclick="mfrPrintBrandedInvoice(&quot;'+esc(i.id)+'&quot;)">Print / Save PDF</button><button class="btn btn-danger" onclick="confirmDeleteInvoice(&quot;'+esc(i.id)+'&quot;)">Delete Invoice</button></div>';
      mfrModal('Invoice '+esc(i.invoice_number||''), actions + renderInvoiceDoc(b), '1040px');
    }catch(e){ console.error(e); toast('Could not load invoice: '+(e.message||e), 'error'); }
  };
  window.mfrPrintBrandedInvoice = async function(id){
    try{
      const b=await loadInvoiceBundle(id);
      const html='<!doctype html><html><head><meta charset="utf-8"><title>Invoice '+esc(b.invoice.invoice_number||'')+'</title><style>body{margin:0;background:#fff;font-family:Inter,Arial,sans-serif;color:#0f172a}@page{size:letter;margin:.35in}.mfr-invoice-doc{box-shadow:none!important;border-radius:0!important;border:0!important}.mfr-invoice-hero{-webkit-print-color-adjust:exact;print-color-adjust:exact}'+(document.querySelector('style')?.innerHTML||'')+'</style></head><body>'+renderInvoiceDoc(b)+'<script>setTimeout(function(){window.print();},300);<\/script></body></html>';
      const w=window.open('', '_blank'); if(!w){ toast('Popup blocked. Use browser print from invoice modal.', 'error'); return; }
      w.document.open(); w.document.write(html); w.document.close();
    }catch(e){ toast('Could not print invoice: '+(e.message||e), 'error'); }
  };
  

/* MFR safe invoice-list refresh helper */
function mfrRefreshInvoicesOrEstimatesList(){
  try{
    const currentPage = (typeof _page !== 'undefined' && _page) ? _page : '';
    const content = document.getElementById('content');
    if(currentPage === 'estimates-list' && typeof pageEstimatesList === 'function' && content){
      return pageEstimatesList(content);
    }
    if(typeof mfrRefreshEstimateSideLists === 'function') return mfrRefreshEstimateSideLists();
  }catch(e){ console.warn('Invoice refresh skipped', e); }
}
window.confirmDeleteInvoice = async function(id){
    try{
      const r=await _sb.from('invoices').select('*').eq('id', id).single(); if(r.error) throw r.error; const i=r.data;
      mfrModal('Delete Invoice '+esc(i.invoice_number||''), '<div class="mfr-danger-note"><strong>This will delete the invoice from Command Center.</strong><br>It will also remove related payment records and unlink line items from this invoice. The original estimate will stay in place.</div><div class="mfr-summary-lines"><div class="mfr-summary-line"><span>Invoice</span><strong>'+esc(i.invoice_number||'Invoice')+'</strong></div><div class="mfr-summary-line"><span>Total</span><strong>'+money(i.total_amount||0)+'</strong></div><div class="mfr-summary-line"><span>Status</span><strong>'+esc(i.status||'sent')+'</strong></div></div><div class="mfr-action-row"><button class="btn btn-outline" onclick="closeModal()">Cancel</button><button class="btn btn-danger" onclick="deleteInvoice(&quot;'+esc(id)+'&quot;)">Delete Invoice</button></div>', '620px');
    }catch(e){ toast('Could not load invoice for delete: '+(e.message||e), 'error'); }
  };
  window.deleteInvoice = async function(id){
    try{
      try{ await _sb.from('invoice_payments').delete().eq('invoice_id', id); }catch(e){}
      try{ await _sb.from('estimate_line_items').update({ invoice_id:null }).eq('invoice_id', id); }catch(e){}
      const del=await _sb.from('invoices').delete().eq('id', id); if(del.error) throw del.error;
      toast('Invoice deleted.', 'success');
      if(typeof closeModal === 'function') closeModal();
      mfrRefreshInvoicesOrEstimatesList();
    }catch(e){ console.error(e); toast('Could not delete invoice: '+(e.message||e), 'error'); }
  };
  const oldMarkPaid = window.markInvoicePaid;
  window.markInvoicePaid = async function(id){
    if(oldMarkPaid) await oldMarkPaid(id);
    try{ await mfrRefreshInvoicesOrEstimatesList(); }catch(e){}
  };
})();
